"use client";

import { useMemo, useState } from "react";
import { Search, SlidersHorizontal, MoreVertical } from "lucide-react";
import { Card, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";

type OvertimeStatus = "Pending" | "Disetujui" | "Ditolak";

interface OvertimeRequest {
  id: string;
  employeeName: string;
  employeeId: string;
  jabatan: string; // kolom pengganti departemen
  subRole?: string; // opsional (mis: "Engineering")
  mulai: string; // untuk tabel: "22 Apr 2026, 18.00"
  selesai: string; // untuk tabel
  mulaiLabel: { date: string; time: string }; // untuk detail
  selesaiLabel: { date: string; time: string };
  totalJam: string; // "3 jam" / "2.5 jam"
  alasan: string;
  status: OvertimeStatus;
  initials: string;
}

function statusStyle(status: OvertimeStatus) {
  switch (status) {
    case "Pending":
      return {
        dot: "bg-orange-500",
        pill: "bg-orange-100 text-orange-700 border-orange-200",
      };
    case "Disetujui":
      return {
        dot: "bg-green-600",
        pill: "bg-green-100 text-green-700 border-green-200",
      };
    case "Ditolak":
      return {
        dot: "bg-red-600",
        pill: "bg-red-100 text-red-700 border-red-200",
      };
  }
}

export default function Page() {
  const requests: OvertimeRequest[] = [
    {
      id: "ot-1",
      employeeName: "Siti Rahmawati",
      employeeId: "EMP-2023-089",
      jabatan: "Senior Developer",
      subRole: "Engineering",
      mulai: "22 Apr 2026, 18.00",
      selesai: "22 Apr 2026, 21.00",
      mulaiLabel: { date: "22 Apr 2026", time: "Pukul 18.00 WIB" },
      selesaiLabel: { date: "22 Apr 2026", time: "Pukul 21.00 WIB" },
      totalJam: "3 jam",
      alasan: "Deployment & bugfix urgent untuk release malam ini.",
      status: "Pending",
      initials: "SR",
    },
    {
      id: "ot-2",
      employeeName: "Andi Pratama",
      employeeId: "EMP-2022-142",
      jabatan: "Marketing Specialist",
      subRole: "Marketing",
      mulai: "21 Apr 2026, 19.30",
      selesai: "21 Apr 2026, 22.00",
      mulaiLabel: { date: "21 Apr 2026", time: "Pukul 19.30 WIB" },
      selesaiLabel: { date: "21 Apr 2026", time: "Pukul 22.00 WIB" },
      totalJam: "2.5 jam",
      alasan: "Persiapan materi kampanye dan revisi konten.",
      status: "Disetujui",
      initials: "AP",
    },
    {
      id: "ot-3",
      employeeName: "Budi Wijaya",
      employeeId: "EMP-2021-085",
      jabatan: "Sales Manager",
      subRole: "Sales",
      mulai: "20 Apr 2026, 18.00",
      selesai: "20 Apr 2026, 20.00",
      mulaiLabel: { date: "20 Apr 2026", time: "Pukul 18.00 WIB" },
      selesaiLabel: { date: "20 Apr 2026", time: "Pukul 20.00 WIB" },
      totalJam: "2 jam",
      alasan: "Follow-up klien untuk closing dan update pipeline.",
      status: "Ditolak",
      initials: "BW",
    },
  ];

  const [q, setQ] = useState("");
  const [jabatanFilter, setJabatanFilter] = useState<string>("Semua");
  const [selectedId, setSelectedId] = useState<string>(requests[0]?.id ?? "");

  const jabatanOptions = useMemo(() => {
    const uniq = Array.from(new Set(requests.map((r) => r.jabatan)));
    return ["Semua", ...uniq];
  }, [requests]);

  const filtered = useMemo(() => {
    return requests.filter((r) => {
      const matchQ =
        `${r.employeeName} ${r.employeeId} ${r.jabatan} ${r.subRole ?? ""}`
          .toLowerCase()
          .includes(q.toLowerCase());

      const matchJabatan = jabatanFilter === "Semua" ? true : r.jabatan === jabatanFilter;

      return matchQ && matchJabatan;
    });
  }, [requests, q, jabatanFilter]);

  const selected = useMemo(() => {
    const found = filtered.find((r) => r.id === selectedId);
    return found ?? filtered[0] ?? null;
  }, [filtered, selectedId]);

  return (
    <div className="w-full bg-[#f6f8fb] p-6">
      <div className="mx-auto grid max-w-[1400px] grid-cols-1 gap-6 lg:grid-cols-[1fr_360px]">
        {/* LEFT */}
        <Card className="rounded-2xl">
          <CardContent className="p-6">
            <div className="flex items-start justify-between gap-4">
              <h1 className="text-xl font-semibold text-slate-900">Persetujuan Lembur</h1>

              {/* Filter Jabatan */}
              <div className="relative">
                <SlidersHorizontal className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-500" />
                <select
                  value={jabatanFilter}
                  onChange={(e) => setJabatanFilter(e.target.value)}
                  className="h-9 rounded-md border border-slate-200 bg-white pl-9 pr-3 text-sm text-slate-800 shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
                  aria-label="Filter Jabatan"
                >
                  {jabatanOptions.map((opt) => (
                    <option key={opt} value={opt}>
                      {opt === "Semua" ? "Filter Jabatan: Semua" : opt}
                    </option>
                  ))}
                </select>
              </div>
            </div>

            {/* Search */}
            <div className="mt-4">
              <div className="relative">
                <Search className="pointer-events-none absolute left-3 top-1/2 h-4 w-4 -translate-y-1/2 text-slate-500" />
                <input
                  value={q}
                  onChange={(e) => setQ(e.target.value)}
                  placeholder="Cari Karyawan"
                  className="h-11 w-full rounded-xl border border-slate-200 bg-white pl-10 pr-4 text-sm text-slate-900 shadow-sm outline-none focus:ring-2 focus:ring-blue-500"
                />
              </div>
            </div>

            {/* Table */}
            <div className="mt-5 overflow-hidden rounded-xl border border-slate-200 bg-white">
              <div className="grid grid-cols-[280px_220px_220px_220px_120px_140px] border-b border-slate-200 bg-slate-50 px-4 py-3 text-[11px] font-semibold uppercase tracking-wide text-slate-600">
                <div>Nama Karyawan</div>
                <div>Jabatan</div>
                <div>Mulai</div>
                <div>Selesai</div>
                <div>Total</div>
                <div>Status</div>
              </div>

              <div className="divide-y divide-slate-100">
                {filtered.map((r) => {
                  const active = selected?.id === r.id;
                  const st = statusStyle(r.status);

                  return (
                    <button
                      key={r.id}
                      onClick={() => setSelectedId(r.id)}
                      className={[
                        "grid w-full grid-cols-[280px_220px_220px_220px_120px_140px] items-center px-4 py-4 text-left",
                        active ? "bg-blue-50" : "bg-white hover:bg-slate-50",
                      ].join(" ")}
                    >
                      <div className="flex items-center gap-3">
                        <div className="flex h-10 w-10 items-center justify-center rounded-full bg-slate-100 text-xs font-semibold text-slate-700">
                          {r.initials}
                        </div>
                        <div className="min-w-0">
                          <div className="truncate text-sm font-semibold text-slate-900">
                            {r.employeeName}
                          </div>
                          <div className="text-xs text-slate-500">ID: {r.employeeId}</div>
                        </div>
                      </div>

                      <div className="min-w-0">
                        <div className="truncate text-sm font-semibold text-slate-900">
                          {r.jabatan}
                        </div>
                        {r.subRole ? (
                          <div className="truncate text-xs text-slate-500">{r.subRole}</div>
                        ) : null}
                      </div>

                      <div className="text-sm text-slate-800">{r.mulai}</div>
                      <div className="text-sm text-slate-800">{r.selesai}</div>

                      <div>
                        <Badge variant="secondary" className="rounded-lg px-3 py-1 text-xs">
                          {r.totalJam}
                        </Badge>
                      </div>

                      <div className="flex items-center gap-2">
                        <span className={`h-2 w-2 rounded-full ${st.dot}`} />
                        <span
                          className={[
                            "inline-flex items-center rounded-lg border px-3 py-1 text-xs font-semibold",
                            st.pill,
                          ].join(" ")}
                        >
                          {r.status}
                        </span>
                      </div>
                    </button>
                  );
                })}
              </div>
            </div>

            <div className="mt-3 text-xs text-slate-500">
              Menampilkan {filtered.length} pengajuan
            </div>
          </CardContent>
        </Card>

        {/* RIGHT (FIXED LAYOUT) */}
        <Card className="rounded-2xl overflow-hidden">
          {/* p-0 supaya footer sticky rapih */}
          <CardContent className="p-0">
            {/* container kolom */}
            <div className="flex flex-col">
              {/* HEADER + BODY */}
              <div className="p-6">
                <div className="flex items-start justify-between">
                  <h2 className="text-sm font-semibold text-slate-900">Detail Pengajuan Lembur</h2>
                  <Button variant="ghost" size="icon" className="h-8 w-8">
                    <MoreVertical className="h-4 w-4 text-slate-600" />
                  </Button>
                </div>

                {/* Employee */}
                <div className="mt-4 rounded-xl border border-slate-200 bg-white p-4">
                  <div className="flex items-center gap-3">
                    <div className="flex h-12 w-12 items-center justify-center rounded-xl bg-slate-100 text-sm font-semibold text-slate-700">
                      {selected?.initials ?? "?"}
                    </div>
                    <div className="min-w-0">
                      <div className="truncate text-sm font-semibold text-slate-900">
                        {selected?.employeeName ?? "-"}
                      </div>
                      <div className="truncate text-xs text-slate-500">
                        {selected?.subRole ? `${selected.subRole} • ` : ""}
                        {selected?.jabatan ?? "-"}
                      </div>
                      <div className="text-xs text-slate-400">{selected?.employeeId ?? ""}</div>
                    </div>
                  </div>
                </div>

                {/* Dates */}
                <div className="mt-5 grid grid-cols-2 gap-4">
                  <div>
                    <div className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                      Mulai
                    </div>
                    <div className="mt-2 text-sm font-semibold text-slate-900">
                      {selected?.mulaiLabel.date ?? "-"}
                    </div>
                    <div className="text-xs text-slate-500">{selected?.mulaiLabel.time ?? ""}</div>
                  </div>

                  <div>
                    <div className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                      Selesai
                    </div>
                    <div className="mt-2 text-sm font-semibold text-slate-900">
                      {selected?.selesaiLabel.date ?? "-"}
                    </div>
                    <div className="text-xs text-slate-500">
                      {selected?.selesaiLabel.time ?? ""}
                    </div>
                  </div>
                </div>

                {/* Total */}
                <div className="mt-5">
                  <div className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                    Total Lembur
                  </div>
                  <div className="mt-2">
                    <Badge variant="secondary" className="rounded-lg px-3 py-1 text-xs">
                      {selected?.totalJam ?? "-"}
                    </Badge>
                  </div>
                </div>

                {/* Reason */}
                <div className="mt-5">
                  <div className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                    Alasan Lembur
                  </div>
                  <div className="mt-2 rounded-xl border border-slate-200 bg-white p-4 text-sm text-slate-700">
                    {selected?.alasan ?? "-"}
                  </div>
                </div>

                {/* Status */}
                <div className="mt-5">
                  <div className="text-[11px] font-semibold uppercase tracking-wide text-slate-500">
                    Status
                  </div>
                  <div className="mt-2 flex items-center gap-2">
                    {selected ? (
                      <>
                        <span
                          className={`h-2 w-2 rounded-full ${statusStyle(selected.status).dot}`}
                        />
                        <span
                          className={[
                            "inline-flex items-center rounded-lg border px-3 py-1 text-xs font-semibold",
                            statusStyle(selected.status).pill,
                          ].join(" ")}
                        >
                          {selected.status}
                        </span>
                      </>
                    ) : (
                      <span className="text-sm text-slate-500">-</span>
                    )}
                  </div>
                </div>
              </div>

              {/* FOOTER (no mt-auto, use normal footer) */}
              <div className="border-t border-slate-200 bg-white p-6">
                <div className="grid grid-cols-2 gap-3">
                  <Button
                    variant="outline"
                    className="h-11 border-red-200 text-red-600 hover:bg-red-50"
                  >
                    Tolak
                  </Button>
                  <Button className="h-11 bg-blue-600 hover:bg-blue-700">Setuju</Button>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}
